const fullText = $input.first().json.Content;

// Split into one piece per "## " heading — no longer depends on line breaks
const parts = fullText.split(/(?=## )/);

// The first piece (before the first "## ") contains the hotel title
const title = parts[0].trim().replace(/^#\s*/, '').trim();

// Everything after that is the actual policy sections
const sections = parts.slice(1);

const output = sections
  .map(section => section.trim())
  .filter(section => section.length > 0)
  .map(section => {
    return {
      json: {
        Content: `${title}\n\n${section}`
      }
    };
  });

return output;
